import { useState, useEffect } from "react";
import { T } from "../../assets/styles/theme";
import { Btn, Card, Badge, Avatar, Input } from "../../components/UI";
import { submitContactMessage, getOrganizations } from "../../api/auth";

// ─── NAVBAR ───────────────────────────────────────────────────────────────────
const NAV_LINKS = ["Home", "About", "Academics", "Achievements", "Members", "Gallery", "Contact"];

const PublicNav = ({ current, onNavigate, onGoToLogin }) => {
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <>
      <nav
        style={{
          position: "fixed",
          top: 0,
          left: 0,
          right: 0,
          zIndex: 1000,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "0 20px",
          height: 66,
          background: "rgba(6,4,15,.92)",
          backdropFilter: "blur(20px)",
          borderBottom: `1px solid ${T.border}`,
        }}
      >
        {/* Logo */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            fontFamily: "Syne",
            fontSize: 18,
            fontWeight: 900,
          }}
        >
          <div
            style={{
              width: 34,
              height: 34,
              background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`,
              borderRadius: 9,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 16,
            }}
          >
            🎓
          </div>
          <span>
            Zenelait<span style={{ color: T.accent }}>InfoTech</span>
          </span>
        </div>

        {/* Desktop Menu */}
        <div
          className="desktop-menu"
          style={{
            display: "flex",
            alignItems: "center",
            gap: 26,
          }}
        >
          {NAV_LINKS.map((l) => (
            <button
              key={l}
              onClick={() => onNavigate(l.toLowerCase())}
              style={{
                background: "none",
                border: "none",
                cursor: "pointer",
                fontSize: 13,
                fontWeight: 500,
                color: current === l.toLowerCase() ? T.accent : T.white,
              }}
            >
              {l}
            </button>
          ))}
        </div>

        {/* Desktop Login Button */}
        <button
          className="desktop-login"
          onClick={onGoToLogin}
          style={{
            background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`,
            border: "none",
            color: "#fff",
            padding: "10px 20px",
            borderRadius: 50,
            fontWeight: 800,
            fontSize: 13,
            cursor: "pointer",
            animation: "pulse 2s infinite",
          }}
        >
          🚀 Login
        </button>

        {/* Mobile Hamburger */}
        <div
          className="mobile-menu-icon"
          onClick={() => setMenuOpen(!menuOpen)}
          style={{
            display: "none",
            fontSize: 22,
            cursor: "pointer",
            color: "#fff",
          }}
        >
          ☰
        </div>
      </nav>

      {/* Mobile Dropdown */}
      {menuOpen && (
        <div
          style={{
            position: "fixed",
            top: 66,
            left: 0,
            right: 0,
            background: "rgba(10,10,20,0.98)",
            backdropFilter: "blur(20px)",
            padding: "20px",
            display: "flex",
            flexDirection: "column",
            gap: 16,
            zIndex: 999,
          }}
        >
          {NAV_LINKS.map((l) => (
            <button
              key={l}
              onClick={() => {
                onNavigate(l.toLowerCase());
                setMenuOpen(false);
              }}
              style={{
                background: "none",
                border: "none",
                textAlign: "left",
                fontSize: 15,
                color: current === l.toLowerCase() ? T.accent : "#fff",
                cursor: "pointer",
              }}
            >
              {l}
            </button>
          ))}

          <button
            onClick={() => {
              onGoToLogin();
              setMenuOpen(false);
            }}
            style={{
              marginTop: 10,
              background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`,
              border: "none",
              color: "#fff",
              padding: "10px",
              borderRadius: 30,
              fontWeight: 700,
              cursor: "pointer",
            }}
          >
            🚀 Login / Register
          </button>
        </div>
      )}

      {/* Responsive CSS */}
      <style>
        {`
          @media (max-width: 768px) {
            .desktop-menu,
            .desktop-login {
              display: none !important;
            }

            .mobile-menu-icon {
              display: block !important;
            }
          }
        `}
      </style>
    </>
  );
};



// ─── FOOTER ───────────────────────────────────────────────────────────────────
const PublicFooter = () => {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handler = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener("resize", handler);
    return () => window.removeEventListener("resize", handler);
  }, []);

  return (
